SELECT start_date, depth
FROM economic_cycles
WHERE unemployment_rate_change > 3;

SELECT DISTINCT ua.user_id, ua.cycle_id
FROM user_access ua
ORDER BY ua.user_id, ua.cycle_id;

SELECT start_date, end_date
FROM economic_cycles
ORDER BY length DESC;

SELECT start_date, depth, unemployment_rate_change
FROM economic_cycles
WHERE cycle_id = 1;

SELECT c.cycle_id, u.username, u.role
FROM collaboration c
JOIN users u ON c.user_id = u.user_id;

SELECT DISTINCT country_code
FROM economic_cycles
WHERE depth < -0.5;
